const raw = $input.first().json;
const data = (raw && raw.data && typeof raw.data === 'string')
  ? JSON.parse(raw.data)
  : (typeof raw === 'string' ? JSON.parse(raw) : raw);
const nextIndex = (data.lastIndex + 1) % data.order.length;
const category = data.order[nextIndex];
return [{ json: { category, nextIndex, rotation: data } }];

const raw = $input.first().json;
const pool = (raw && raw.data && typeof raw.data === 'string')
  ? JSON.parse(raw.data)
  : (typeof raw === 'string' ? JSON.parse(raw) : raw);
const cat = $('Pick Category').item.json.category;

let candidates = pool.topics.filter(t => !t.lastUsedAt);
if (candidates.length === 0) {
  candidates = [...pool.topics].sort((a, b) =>
    new Date(a.lastUsedAt) - new Date(b.lastUsedAt)
  );
}
const topic = candidates[0];

const today = new Date().toISOString().slice(0, 10);
const ymonth = today.slice(0, 7);
const topicStub = topic.id;
const i18nKey = `${cat}-${topicStub.replace(/^[a-z]+-/, '')}-${ymonth}`;

return [{ json: { topic, category: cat, today, i18nKey } }];

function unwrap(raw) {
  if (raw && raw.data !== undefined) return raw.data;
  return raw;
}
function toText(v) { return typeof v === 'string' ? v : JSON.stringify(v); }
function toObj(v) {
  if (typeof v === 'string') { try { return JSON.parse(v); } catch { return {}; } }
  return v;
}

const masterText = toText(unwrap($('Fetch master prompt').first().json));
const categoryText = toText(unwrap($('Fetch category prompt').first().json));
const links = toObj(unwrap($('Fetch internal links').first().json));
const topicData = $('Pick Topic').first().json;

const categorySlugs = (links.byCategory && links.byCategory[topicData.category]) || [];
const internalLinks = categorySlugs.map(slug => {
  const svc = (links.services || []).find(s => s.slug === slug);
  return { slug, label: svc?.label || slug, url: `https://www.roibase.com.tr/tr/${slug}` };
});

const userPrompt = [
  `TOPIC_TITLE: ${topicData.topic.title}`,
  `TOPIC_ANGLE: ${topicData.topic.angle}`,
  `CATEGORY: ${topicData.category}`,
  `TODAY: ${topicData.today}`,
  `I18N_KEY: ${topicData.i18nKey}`,
  `INTERNAL_LINKS: ${JSON.stringify(internalLinks)}`,
  '',
  '--- KATEGORI YONERGESI ---',
  categoryText
].join('\n');

return [{ json: { system: masterText, user: userPrompt, topicData } }];

const raw = $input.first().json;
const resp = (raw && raw.data && typeof raw.data === 'object') ? raw.data : raw;
const rawText = resp.content?.[0]?.text || JSON.stringify(resp);
const topicData = $('Build Claude prompt').first().json.topicData;

// Defensive cleaning: Claude bazen markdown code fence ile sarar veya
// frontmatter'dan önce 'İşte makale:' gibi giriş cümlesi ekler. Aşağıdaki
// adımlar bunları temizleyip frontmatter regex'inin tutmasını sağlar.
let text = rawText;
// 1) Markdown code fence (```markdown veya ```yaml veya ```)
text = text.replace(/^\s*```[a-z]*\n/i, '').replace(/\n```\s*$/, '');
// 2) Frontmatter başlangıcına kadar her şeyi at (---\n satırı bulunana kadar)
const frontmatterStart = text.indexOf('---\n');
if (frontmatterStart > 0) {
  text = text.slice(frontmatterStart);
} else if (frontmatterStart < 0) {
  // Hiç frontmatter yoksa olduğu gibi bırak (parse fail-safe)
  text = rawText;
}

const m = text.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
const frontmatter = m ? m[1] : '(parse failed)';
const body = m ? m[2] : text;

// Title regex 3 senaryoyu sırayla dener: "...", '...', tırnaksız.
// Apostrof title'ın parçasıysa (örn ChatGPT'nin) çift tırnak içinde sorun yok.
let titleMatch = frontmatter.match(/title:\s*"([^"]+)"/);
if (!titleMatch) titleMatch = frontmatter.match(/title:\s*'([^']+)'/);
if (!titleMatch) titleMatch = frontmatter.match(/title:\s*([^\n]+)/);
const title = titleMatch ? titleMatch[1].trim() : '(unknown)';

const slug = title.toLowerCase()
  .replace(/ı/g, 'i').replace(/ğ/g, 'g').replace(/ü/g, 'u')
  .replace(/ş/g, 's').replace(/ö/g, 'o').replace(/ç/g, 'c')
  .replace(/'/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .slice(0, 70);

return [{
  json: {
    parsedTitle: title,
    parsedSlug: slug,
    parsedFrontmatter: frontmatter,
    parsedBody: body,
    bodyLength: body.length,
    bodyWordCount: body.split(/\s+/).filter(Boolean).length,
    targetPath: `content/tr/${topicData.category}/${slug}.md`,
    rawResponse: rawText,
    cleanedText: text,
    topicData
  }
}];

function unwrap(raw) { return (raw && raw.data !== undefined) ? raw.data : raw; }
function toText(v) { return typeof v === 'string' ? v : JSON.stringify(v); }

const translatePromptText = toText(unwrap($('Fetch translate prompt').first().json));
const trData = $('Parse TR output').first().json;
const trRaw = trData.rawResponse;

const languages = [
  { code: 'en', name: 'English' },
  { code: 'de', name: 'Deutsch' },
  { code: 'es', name: 'Español' },
  { code: 'fr', name: 'Français' },
  { code: 'it', name: 'Italiano' },
  { code: 'ru', name: 'Русский' }
];

return languages.map(lang => {
  const system = translatePromptText
    .replace(/\{\{TARGET_LANG\}\}/g, lang.code)
    .replace(/\{\{TARGET_LANG_NAME\}\}/g, lang.name);
  return {
    json: {
      targetLang: lang.code,
      targetLangName: lang.name,
      system,
      user: trRaw
    }
  };
});

function unwrapResp(raw) { return (raw && raw.data && typeof raw.data === 'object') ? raw.data : raw; }

const items = $input.all();
const payloadItems = $('Build translate payloads').all();

const parsed = items.map((item, idx) => {
  const resp = unwrapResp(item.json);
  const rawText = resp.content?.[0]?.text || JSON.stringify(resp);
  const targetLang = payloadItems[idx]?.json?.targetLang || 'unknown';

  // Defensive cleaning (aynı master parse mantığı)
  let text = rawText;
  text = text.replace(/^\s*```[a-z]*\n/i, '').replace(/\n```\s*$/, '');

  // Extract SLUG: line
  const slugMatch = text.match(/^SLUG:\s*([a-z0-9-]+)/m);
  const slug = slugMatch ? slugMatch[1] : `unknown-${targetLang}`;

  // Strip SLUG line + everything before frontmatter
  text = text.replace(/^SLUG:\s*[a-z0-9-]+\s*\n/m, '');
  const fmStart = text.indexOf('---\n');
  if (fmStart > 0) text = text.slice(fmStart);

  const m = text.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
  const frontmatter = m ? m[1] : '(parse failed)';
  const body = m ? m[2] : text;

  let titleMatch = frontmatter.match(/title:\s*"([^"]+)"/);
  if (!titleMatch) titleMatch = frontmatter.match(/title:\s*'([^']+)'/);
  if (!titleMatch) titleMatch = frontmatter.match(/title:\s*([^\n]+)/);
  const title = titleMatch ? titleMatch[1].trim() : '(unknown)';

  const fullContent = `---\n${frontmatter}\n---\n${body}`;

  return {
    json: {
      lang: targetLang,
      slug,
      title,
      frontmatter,
      body,
      fullContent,
      bodyLength: body.length,
      bodyWordCount: body.split(/\s+/).filter(Boolean).length,
      rawResponse: rawText
    }
  };
});

return parsed;

const trData = $('Parse TR output').first().json;
const translations = $input.all().map(i => i.json);
const topicData = trData.topicData;
const category = topicData.category;
const i18nKey = topicData.i18nKey;

const files = [
  {
    lang: 'tr',
    slug: trData.parsedSlug,
    path: `content/tr/${category}/${trData.parsedSlug}.md`,
    content: trData.rawResponse,
    wordCount: trData.bodyWordCount
  },
  ...translations.map(t => ({
    lang: t.lang,
    slug: t.slug,
    path: `content/${t.lang}/${category}/${t.slug}.md`,
    content: t.fullContent,
    wordCount: t.bodyWordCount
  }))
];

const summary = {
  i18nKey,
  category,
  topicTitle: topicData.topic.title,
  fileCount: files.length,
  totalWords: files.reduce((sum, f) => sum + f.wordCount, 0),
  files: files.map(f => ({ lang: f.lang, slug: f.slug, path: f.path, wordCount: f.wordCount })),
  dryRun: true,
  notice: 'GitHub commit henüz aktif değil — Faz B2da eklenecek'
};

return [{ json: { summary, files } }];

// 9-file commit manifest: 7 makale + rotation state + topic-pool state
const agg = $input.first().json;
const trData = $('Parse TR output').first().json;
const pickCategoryData = $('Pick Category').first().json;
const pickTopicData = $('Pick Topic').first().json;

function unwrap(raw) { return (raw && raw.data !== undefined) ? raw.data : raw; }
function toObj(v) {
  if (typeof v === 'string') { try { return JSON.parse(v); } catch { return {}; } }
  return v;
}

const poolRaw = $('Fetch topic pool').first().json;
const pool = toObj(unwrap(poolRaw));

// Rotation güncelle
const rotation = pickCategoryData.rotation;
const nextIndex = pickCategoryData.nextIndex;
const nowIso = new Date().toISOString();
const usedTopic = pickTopicData.topic;

const newRotation = {
  ...rotation,
  lastIndex: nextIndex,
  lastRunAt: nowIso,
  history: [
    ...(rotation.history || []),
    { at: nowIso, category: pickCategoryData.category, topicId: usedTopic.id, i18nKey: pickTopicData.i18nKey }
  ].slice(-50)  // son 50 run'ı tut, sınırsız büyümesin
};

// Topic-pool güncelle (kullanılan topic'in lastUsedAt'i)
const newPool = {
  ...pool,
  topics: (pool.topics || []).map(t =>
    t.id === usedTopic.id ? { ...t, lastUsedAt: nowIso } : t
  )
};

const commitFiles = [
  ...agg.files.map(f => ({ path: f.path, content: f.content })),
  { path: 'scripts/category-rotation.json', content: JSON.stringify(newRotation, null, 2) + '\n' },
  { path: `scripts/topic-pool/${pickCategoryData.category}.json`, content: JSON.stringify(newPool, null, 2) + '\n' }
];

const commitMessage = `Auto: ${pickCategoryData.category} — ${trData.parsedTitle}\n\nTopic ID: ${usedTopic.id}\ni18nKey: ${pickTopicData.i18nKey}\nFiles: ${commitFiles.length} (${agg.files.length} articles + 2 metadata)`;

return [{
  json: {
    files: commitFiles,
    message: commitMessage,
    fileCount: commitFiles.length,
    summary: agg.summary
  }
}];

// Manifest'teki dosyaları blob create için ayrı item'lara böl
const manifest = $('Build commit manifest').first().json;
return manifest.files.map(f => ({
  json: {
    path: f.path,
    content: f.content,
    contentBase64: Buffer.from(f.content, 'utf-8').toString('base64')
  }
}));

// Blob SHA'larını dosya path'leriyle eşleştir, tree array'i kur
const blobItems = $input.all();
const splitItems = $('Split files for blobs').all();

const tree = blobItems.map((item, idx) => {
  const blobResp = (item.json && item.json.data && typeof item.json.data === 'object') ? item.json.data : item.json;
  const path = splitItems[idx].json.path;
  return {
    path,
    mode: '100644',
    type: 'blob',
    sha: blobResp.sha
  };
});

const baseTreeSha = $('Get current commit').first().json.tree.sha;

return [{ json: { base_tree: baseTreeSha, tree } }];

