// Final summary: commit hash + push tamamlandı
const refResp = $input.first().json;
const manifest = $('Build commit manifest').first().json;
const commitData = $('Create commit').first().json;

return [{
  json: {
    success: true,
    commitSha: commitData.sha,
    commitUrl: commitData.html_url,
    refUpdated: refResp.ref || refResp.object?.sha,
    fileCount: manifest.fileCount,
    message: manifest.message.split('\n')[0],
    summary: manifest.summary,
    completedAt: new Date().toISOString()
  }
}];
